// sw.js — Service Worker
const CACHE_NAME = 'app-v1';
const STATIC_ASSETS = ['/', '/index.html', '/styles.css', '/app.js', '/manifest.json'];

// Install — pre-cache static assets
self.addEventListener('install', (e) => {
  e.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(STATIC_ASSETS))
  );
  self.skipWaiting();
});

// Activate — clean old caches
self.addEventListener('activate', (e) => {
  e.waitUntil(
    caches.keys().then(keys => Promise.all(
      keys.filter(k => k !== CACHE_NAME).map(k => caches.delete(k))
    ))
  );
  self.clients.claim();
});

// Fetch — Stale-While-Revalidate for pages, Cache-First for assets
self.addEventListener('fetch', (e) => {
  const url = new URL(e.request.url);
  if (url.pathname.startsWith('/api/')) {
    // Network-First for API
    e.respondWith(
      fetch(e.request).then(res => {
        const clone = res.clone();
        caches.open(CACHE_NAME).then(c => c.put(e.request, clone));
        return res;
      }).catch(() => caches.match(e.request))
    );
  } else {
    // Cache-First for static assets
    e.respondWith(
      caches.match(e.request).then(cached => cached || fetch(e.request))
    );
  }
});

// Offline data store with IndexedDB
import { openDB } from 'idb';

const db = await openDB('app-store', 1, {
  upgrade(db) {
    db.createObjectStore('items', { keyPath: 'id' });
    db.createObjectStore('queue', { keyPath: 'id', autoIncrement: true });
  },
});

// Save locally + queue for sync
async function saveItem(item: Item) {
  await db.put('items', item);
  if (!navigator.onLine) {
    await db.add('queue', { action: 'save', data: item, timestamp: Date.now() });
  } else {
    await fetch('/api/items', { method: 'POST', body: JSON.stringify(item) });
  }
}

// Sync queue when back online
window.addEventListener('online', async () => {
  const queue = await db.getAll('queue');
  for (const op of queue) {
    await fetch('/api/items', { method: 'POST', body: JSON.stringify(op.data) });
    await db.delete('queue', op.id);
  }
});

// Offline indicator component
function OfflineBanner() {
  const [online, setOnline] = useState(navigator.onLine);
  useEffect(() => {
    const on = () => setOnline(true);
    const off = () => setOnline(false);
    window.addEventListener('online', on);
    window.addEventListener('offline', off);
    return () => { window.removeEventListener('online', on); window.removeEventListener('offline', off); };
  }, []);
  if (online) return null;
  return <div className="fixed top-0 w-full bg-amber-500 text-white text-center py-1 text-sm z-50">You're offline — changes will sync when connected</div>;
}

// Request permission and subscribe
async function subscribeToPush() {
  const permission = await Notification.requestPermission();
  if (permission !== 'granted') return null;

  const registration = await navigator.serviceWorker.ready;
  const subscription = await registration.pushManager.subscribe({
    userVisibleOnly: true,
    applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
  });

  // Send subscription to backend
  await fetch('/api/push/subscribe', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(subscription),
  });
  return subscription;
}

// In service worker — handle push event
self.addEventListener('push', (e) => {
  const data = e.data?.json() ?? { title: 'New notification' };
  e.waitUntil(
    self.registration.showNotification(data.title, {
      body: data.body,
      icon: '/icons/icon-192.png',
      badge: '/icons/badge-72.png',
      data: { url: data.url ?? '/' },
    })
  );
});

self.addEventListener('notificationclick', (e) => {
  e.notification.close();
  e.waitUntil(clients.openWindow(e.notification.data.url));
});
